3. public class DiscountCalculator
4. {
5.     /// <summary>
6.     /// Applies a tiered discount based on order total.
7.     /// Orders >= 1000 get 15%, >= 500 get 10%, >= 100 get 5%, below 100 get 0%.
8.     /// </summary>
9.     public decimal CalculateDiscount(decimal orderTotal)
10.     {
11.         if (orderTotal < 0)
12.             throw new ArgumentOutOfRangeException(nameof(orderTotal), "Order total cannot be negative");
13. 
14.         if (orderTotal >= 1000m)
15.             return orderTotal * 0.15m;
16.         if (orderTotal >= 500m)
17.             return orderTotal * 0.10m;
18.         if (orderTotal >= 100m)
19.             return orderTotal * 0.05m;
20. 
21.         return 0m;
22.     }
23. 
24.     /// <summary>
25.     /// Calculates shipping cost. Free shipping for orders over 250.
26.     /// Express adds 50% surcharge. Items over 10kg add a heavy item fee.
27.     /// </summary>
28.     public decimal CalculateShipping(decimal orderTotal, double weightKg, bool express)
29.     {
30.         if (orderTotal <= 0)
31.             throw new ArgumentOutOfRangeException(nameof(orderTotal));
32.         if (weightKg <= 0)
33.             throw new ArgumentOutOfRangeException(nameof(weightKg));
34. 
35.         if (orderTotal > 250m)
36.             return 0m;
37. 
38.         decimal baseCost = 5.00m + (decimal)(weightKg * 0.50);
39. 
40.         if (weightKg > 10.0)
41.             baseCost += 15.00m;
42. 
43.         if (express)
44.             baseCost *= 1.50m;
45. 
46.         return baseCost;
47.     }
48. 
49.     /// <summary>
50.     /// Applies a coupon code. Returns the adjusted total after coupon.
51.     /// Coupons cannot reduce the total below 1.00.
52.     /// </summary>
53.     public decimal ApplyCoupon(decimal total, string couponCode)
54.     {
55.         ArgumentNullException.ThrowIfNull(couponCode);
56. 
57.         if (total <= 0)
58.             throw new ArgumentOutOfRangeException(nameof(total));
59. 
60.         decimal discount = couponCode.ToUpperInvariant() switch
61.         {
62.             "SAVE10" => total * 0.10m,
63.             "SAVE20" => total * 0.20m,
64.             "FLAT5" => 5.00m,
65.             "FLAT50" => 50.00m,
66.             _ => 0m
67.         };
68. 
69.         decimal result = total - discount;
70.         return result < 1.00m ? 1.00m : result;
71.     }
72. }
