54.     // Tests free shipping for a large order, but never tests the boundary at 250.
55.     // Does not test heavy item fee boundary at 10kg.
56.     // Does not test the express surcharge.
57. 
58.     [TestMethod]
59.     public void CalculateShipping_LargeOrder_FreeShipping()
60.     {
61.         var calc = new DiscountCalculator();
